SELECT domain_nickname, domain_avatar_url, domain_contact_phone, domain_contact_email
FROM domain_member
WHERE staff_account_id = #{staffAccountId}
  AND business_domain_id = #{domainId}
  AND deleted_at IS NULL
LIMIT 1

SELECT id FROM domain_member
WHERE business_domain_id = #{businessDomainId}
  AND staff_account_id = #{staffAccountId}
  AND deleted_at IS NULL
LIMIT 1
